  ('heelevel3-7c4986e7-moex-00025', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X0年1月1日以$1,550,000發行面額$1,500,000可轉換公司債，票面利率10%，每 年年底付息，發行期限 5 年，轉換價格為$120。經評估未含轉換權之公司債公允價值為 $1,519,000，轉換權公允價值為$35,000。甲公司另行支付交易成本$25,000。甲公司發行可轉 換公司債時應認列認股權資本公積為多少？', '["$30,427", "$30,500", "$31,000", "$35,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00026', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年初向乙公司承租一輛貨車，租期4年，每年底支付租金$100,000，並約定甲公 司可於租約期滿以$20,000購買此貨車，甲公司可以合理確定將行使此選擇權。甲公司估計該 貨車於租約期滿後可以再使用2年，無殘值，採直線法提列折舊。X1年初，甲公司為安排此 租賃而支付原始直接成本$30,000。甲公司無法得知該租賃之隱含利率，其增額借款利率為 8%。折現率8%之複利現值因子與年金現值因子如下表所示。 4年期 6年期 複利現值因子 0.7350 0.6302 年金現值因子 3.3121 4.6229 甲公司X1年之會計處理，下列何者錯誤？', '["X1年初認列租賃負債$345,910", "X1年初認列使用權資產$375,910", "X1年利息費用$27,673", "X1年折舊費用$93,978 22340"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00027', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '下列那（些）項目屬於甲公司的存貨？', '["甲公司銷售商品予乙客戶，約定起運點交貨，該批商品目前正在運送途中", "甲公司自丙供應商購入商品，約定起運點交貨，該批商品目前正在運送途中", "甲公司受丁公司委託代為銷售一批商品，該批商品目前存放於甲公司倉庫中", "甲公司銷售商品予戊客戶，雙方約定於3個月後，甲公司依原售價加計5%購回該批商品"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00028', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年1月1日以公允價值$963,550購入乙公司4年期公司債，並將之分類為按攤 銷後成本衡量之金融資產，另支付交易成本$1,800。該債券面額$1,000,000，票面利率 5%， 每年 12 月 31 日付息一次，設算市場利率為 6%。甲公司在 X2 年 9 月 30 日以公允價值 $1,023,768（含應計利息）出售該債券投資，並支付交易成本$1,850。上述交易對甲公司X2年 之綜合損益的影響為何？', '["$6,700", "$42,350", "$48,561", "$48,647"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00029', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司在X1年初以$100,000購得A設備，估計使用年限5年，殘值$2,000，採雙倍數餘額 遞減法提列折舊，並以月為計算折舊單位。X3年10月1日，甲公司以A設備交換乙公司之 B機器，並支付現金$13,000，B機器之公允價值為$40,000，且甲公司判斷該交換具商業實質。 甲公司應認列A設備之處分損益為多少？', '["$0", "利益$1,464", "利益$1,800", "利益$14,800"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00030', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司為電腦製造商，每台電腦售價$28,500，並附一年期保固維修服務。為服務客戶，甲公 司另推出二年期保固合約，單獨售價為$1,500。若客戶購買電腦時加購二年期保固合約，則除 原有一年期保固服務外，可再延長二年保固服務（共計三年保固服務），合購價$29,000。經甲 公司分析研判，一年期保固服務屬於保證型保固，平均維修成本為$1,200；二年期保固服務則 屬於勞務型保固。甲公司於X1年共出售200台電腦，其中120台電腦有加購二年期保固合 約，另外80台電腦則未加購二年期保固合約。甲公司X1年之電腦銷貨收入為多少？', '["$5,520,000", "$5,586,000", "$5,760,000", "$5,880,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00031', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', 'X1年底，甲公司有存貨：製成品1,500件，每件成本$40；原料1,000件，每件成本$25，每 件原料需再投入加工成本$17才能成為製成品。銷售費用為每件$2，正常售價為每件$43。甲 公司與乙客戶在X1年9月簽訂不可撤銷合約，將於X2年1月以每件$45銷售1,200件製成 品予乙客戶。甲公司X1年期末存貨之淨變現價值為多少？', '["製成品$60,000，原料$25,000", "製成品$61,500，原料$26,000", "製成品$63,900，原料$24,000", "製成品$66,900，原料$23,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00032', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司會計人員估算 X1 年可售商品零售價為$560,000，並以加權平均零售價法計算成本比 率為70%，且依此估算期末存貨成本為$52,500。然經再次檢視相關資料發現估算期末存貨成 本時忽略 X1 年曾將一批商品退回給供應商，該批商品成本為$5,660，零售價為$12,000；另 有員工折扣$5,000亦被忽略。經修正後，甲公司估算X1年期末存貨成本應為多少？', '["$40,890", "$44,415", "$47,940", "$57,007"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00033', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-d3ff7f6b', 'sub-heelevel3-7c4986e7-03', NULL, 'essay', '考慮兩家生產同質商品的廠商進行數量競爭（quantity competition），並
